import {
  Box,
  Button,
  ButtonGroup,
  Flex,
  Grid,
  IconButton,
  Select,
  Text,
  useBreakpointValue,
  Input,
} from "@chakra-ui/react";
import React, { useEffect, useState } from "react";
import { Link } from "react-router-dom";
import { Table, Thead, Tbody, Tr, Th, Td } from "@chakra-ui/react";
import { AddIcon, EditIcon, DeleteIcon } from "@chakra-ui/icons";
import { useDispatch, useSelector } from "react-redux";
import convertDateFormat, {
  deleteProduct,
  getProduct,
} from "../../Redux/AdminReducer/action";
import Pagination from "../Adminitems/Pagination";
import TeacherNavTop from "./TeacherNavTop";

export default function TeacherCourses() {
  const store = useSelector((store) => store.TeacherReducer.data);
  const dispatch = useDispatch();

  const [page, setPage] = useState(1);
  const [search, setSearch] = useState("");
  const [order, setOrder] = useState("");

  const limit = 4;

  const tableSize = useBreakpointValue({ base: "sm", md: "md" });

  useEffect(() => {
    dispatch(getProduct(page, limit, search, order));
  }, [page, search, order, limit]);

  const handleDelete = (id, title) => {
    dispatch(deleteProduct(id));
    alert(`${title} is Deleted`);
  };

  const handlePageChange = (page) => setPage(page);

  const handlePageButton = (val) => {
    setPage((prev) => prev + val);
  };

  const count = 4;

  return (
    <Box bg="#f7f9fa" minH="100vh">
      <TeacherNavTop handleSearch={(e) => setSearch(e.target.value)} />

      <Box maxW="1200px" mx="auto" mt="100px" px={4}>
        {/* HEADER */}
        <Flex
          justify="space-between"
          align="center"
          mb={6}
          flexWrap="wrap"
          gap={4}
        >
          <Text fontSize="2xl" fontWeight="bold">
            Your Courses
          </Text>

          <Flex gap={3}>
            <Select
              bg="white"
              borderRadius="md"
              w="200px"
              onChange={(e) => setOrder(e.target.value)}
            >
              <option value="">Sort by</option>
              <option value="asc">Price ↑</option>
              <option value="desc">Price ↓</option>
            </Select>

            <Link to="/Teacher/addCourse">
              <Button
                leftIcon={<AddIcon />}
                bg="#A435F0"
                color="white"
                _hover={{ bg: "#8710d8" }}
              >
                Create Course
              </Button>
            </Link>
          </Flex>
        </Flex>

        {/* TABLE CARD */}
        <Box
          bg="white"
          borderRadius="lg"
          boxShadow="lg"
          p={4}
          overflowX="auto"
        >
          <Table variant="simple" size={tableSize}>
            <Thead bg="#f7f9fa">
              <Tr>
                <Th>Title</Th>
                <Th>Date</Th>
                <Th>Category</Th>
                <Th>Description</Th>
                <Th isNumeric>Price</Th>
                <Th>Teacher</Th>
                <Th textAlign="center">Actions</Th>
              </Tr>
            </Thead>

            <Tbody>
              {store?.map((el) => (
                <Tr
                  key={el._id}
                  _hover={{ bg: "#f9f9f9" }}
                  transition="0.2s"
                >
                  <Td fontWeight="medium">{el.title}</Td>
                  <Td>{convertDateFormat(el.createdAt)}</Td>
                  <Td>{el.category}</Td>
                  <Td maxW="250px" isTruncated>
                    {el.description}
                  </Td>
                  <Td isNumeric fontWeight="bold">
                    ${el.price}
                  </Td>
                  <Td>{el.teacher}</Td>

                  <Td>
                    <Flex justify="center" gap={2}>
                      <IconButton
                        icon={<DeleteIcon />}
                        colorScheme="red"
                        variant="outline"
                        onClick={() =>
                          handleDelete(el._id, el.title)
                        }
                      />

                      <Link to={`/Teacher/edit/${el._id}`}>
                        <IconButton
                          icon={<EditIcon />}
                          bg="#A435F0"
                          color="white"
                          _hover={{ bg: "#8710d8" }}
                        />
                      </Link>
                    </Flex>
                  </Td>
                </Tr>
              ))}
            </Tbody>
          </Table>
        </Box>

        {/* PAGINATION */}
        <Flex justify="space-between" mt={6} align="center">
          <Button
            onClick={() => handlePageButton(-1)}
            isDisabled={page <= 1}
          >
            Prev
          </Button>

          <Pagination
            totalCount={count}
            current_page={page}
            handlePageChange={handlePageChange}
          />

          <Button
            onClick={() => handlePageButton(1)}
            isDisabled={page >= count}
          >
            Next
          </Button>
        </Flex>
      </Box>
    </Box>
  );
}
